Javascript.initialise:

defNode = WPU.getSubjectPartyNode();
var solId = XML.getNodeTextContent(defNode.selectSingleNode("./SolicitorSurrogateId"));			
solNode = null;
if( null != solId && "" != solId)
{	solNode = Services.getNode("//ManageCase/Parties/Solicitor[SurrogateId = '"+solId+"']");
}

Javascript.logic:
if('ACK' != Services.getValue(NewAddressForService.dataBinding))
{	Services.setValue(SolName.dataBinding, "");
}
else
{	//check if a solicitor exisits for this defendant
	if( null != solNode )
    {	var solNameNode = solNode.selectSingleNode("./Name");
    	if( null != solNameNode)
    	Services.setValue(SolName.dataBinding, XML.getNodeTextContent( solNameNode ));
    }				
}

Javascript.miscCode:
areAddressFieldsReadOnly = function()
{
	if('ACK' == Services.getValue(NewAddressForService.dataBinding))
	{
		// UCT Defect 774 - read only solicitor if coded party
		if( null != solNode )
	    {
			var code = XML.selectNodeGetTextContent( solNode, "./Code" );
    		if( null != code && "" != code )    		
    		{
    			return true;
    		}
    	}
    }
    return false;
}
